#include "base/memory/ace_type.h"
#include "base/memory/referenced.h"
#include "core/components_ng/pattern/list/list_pattern.h"
#include "core/components_ng/pattern/list/list_layout_algorithm.h"

namespace OHOS::Ace::NG {

class ListPattern : public Pattern {
public:
    void OnAttachToFrameNode() override {
        auto host = GetHost();
        CHECK_NULL_VOID(host);
        auto pipeline = host->GetContext();
        CHECK_NULL_VOID(pipeline);

        scrollable_ = new ListScrollable(AceType::WeakClaim(this));
        scrollable_->Initialize();
    }

    void OnDetachFromFrameNode() override {
        if (scrollable_) {
            delete scrollable_;
            scrollable_ = nullptr;
        }
    }

    RefPtr<LayoutAlgorithm> CreateLayoutAlgorithm() override {
        auto layoutInfo = AceType::DynamicCast<ListLayoutInfo>(layoutInfo_);
        auto algorithm = AceType::MakeRefPtr<ListLayoutAlgorithm>(layoutInfo);
        algorithm->SetStartIndex(startIndex_);
        algorithm->SetEndIndex(endIndex_);
        return algorithm;
    }

    void UpdateScrollPosition(float offset) {
        auto layoutInfo = AceType::DynamicCast<ListLayoutInfo>(layoutInfo_);
        layoutInfo->UpdateOffset(offset);
        MarkDirtyNode(PROPERTY_UPDATE_MEASURE);
    }

    void OnScrolled(int32_t index, float offset) {
        auto listener = listener_;
        listener->OnScroll(index, offset);
    }

    void SetOnScrollListener(const RefPtr<ScrollListener>& listener) {
        listener_ = listener;
    }

private:
    ListScrollable* scrollable_ = nullptr;
    RefPtr<ListLayoutInfo> layoutInfo_;
    RefPtr<ScrollListener> listener_;
    int32_t startIndex_ = 0;
    int32_t endIndex_ = 0;
};

}
