#include "base/task/task_executor.h"
#include "core/components_ng/pattern/progress/progress_pattern.h"
#include "core/components_ng/pattern/progress/progress_layout_property.h"
#include "core/pipeline_ng/pipeline_context.h"

namespace OHOS::Ace::NG {

class ProgressPattern : public Pattern {
    DECLARE_ACE_TYPE(ProgressPattern, Pattern);

public:
    ProgressPattern() {
        auto pipeline = PipelineContext::GetCurrentContext();
        auto theme = pipeline->GetTheme<ProgressTheme>();
        defaultColor_ = theme->GetColor();
        trackColor_ = theme->GetTrackColor();
    }

    void OnModifyDone() override {
        auto host = GetHost();
        auto layoutProp = host->GetLayoutProperty<ProgressLayoutProperty>();

        auto value = layoutProp->GetValue().value_or(0.0);
        auto maxValue = layoutProp->GetMaxValue().value_or(100.0);

        if (maxValue != 0) {
            progress_ = value / maxValue;
        }

        executor_->PostTask([this]() {
            auto pipeline = PipelineContext::GetCurrentContext();
            auto animationMgr = pipeline->GetAnimationManager();
            animationMgr->AnimateProgress(AceType::Claim(this), progress_);
        }, TaskExecutor::TaskType::UI);
    }

    void OnAttachToFrameNode() override {
        auto host = GetHost();
        auto hub = host->GetOrCreateEventHub<EventHub>();
        hub->AddOnAppear([this]() {
            StartProgressAnimation();
        });
    }

    void StartProgressAnimation() {
        auto anim = AceType::MakeRefPtr<CurveAnimation<float>>(0.0f, progress_, Curves::EASE);
        anim->AddListener([this](float value) {
            animatedProgress_ = value;
            auto host = GetHost();
            host->MarkDirtyNode(PROPERTY_UPDATE_RENDER);
        });
        anim->Play();
    }

private:
    float progress_ = 0.0f;
    float animatedProgress_ = 0.0f;
    Color defaultColor_;
    Color trackColor_;
    RefPtr<TaskExecutor> executor_;
};

}
