#include "core/components_ng/pattern/checkbox/checkbox_pattern.h"
#include "core/components_ng/pattern/checkbox/checkbox_layout_property.h"
#include "core/components_ng/pattern/checkbox/checkbox_paint_property.h"

namespace OHOS::Ace::NG {

class CheckBoxPattern : public Pattern {
    DECLARE_ACE_TYPE(CheckBoxPattern, Pattern);

public:
    void OnModifyDone() override {
        auto host = GetHost();
        CHECK_NULL_VOID(host);

        auto layoutProp = host->GetLayoutProperty<CheckBoxLayoutProperty>();
        CHECK_NULL_VOID(layoutProp);

        auto paintProp = host->GetPaintProperty<CheckBoxPaintProperty>();
        CHECK_NULL_VOID(paintProp);

        auto newChecked = layoutProp->GetIsChecked().value_or(false);
        if (newChecked != isChecked_) {
            isChecked_ = newChecked;
            paintProp->UpdateIsChecked(newChecked);
            host->MarkDirtyNode(PROPERTY_UPDATE_RENDER);
            FireChangeEvent(newChecked);
        }
    }

    void OnAttachToFrameNode() override {
        auto host = GetHost();
        CHECK_NULL_VOID(host);

        auto hub = host->GetOrCreateEventHub<EventHub>();
        CHECK_NULL_VOID(hub);

        hub->SetGestureActuator(
            [weak = AceType::WeakClaim(this)](const GestureEvent& info) {
                auto pattern = weak.Upgrade();
                CHECK_NULL_VOID(pattern);
                auto host = pattern->GetHost();
                CHECK_NULL_VOID(host);
                pattern->ToggleChecked(host);
            });
    }

    void ToggleChecked(const RefPtr<FrameNode>& host) {
        auto layoutProp = host->GetLayoutProperty<CheckBoxLayoutProperty>();
        CHECK_NULL_VOID(layoutProp);

        auto newState = !isChecked_;
        layoutProp->UpdateIsChecked(newState);
        host->MarkDirtyNode(PROPERTY_UPDATE_MEASURE_SELF);
    }

private:
    bool isChecked_ = false;

    void FireChangeEvent(bool checked) {
        auto host = GetHost();
        CHECK_NULL_VOID(host);
        auto hub = host->GetOrCreateEventHub<EventHub>();
        CHECK_NULL_VOID(hub);
        auto listener = hub->GetOnChangeListener();
        if (listener) {
            listener(checked);
        }
    }
};

}
