#include "core/components_ng/pattern/text_field/text_field_pattern.h"
#include "base/task/task_executor.h"

namespace OHOS::Ace::NG {

class OnTextChangedListenerImpl {
public:
    OnTextChangedListenerImpl(WeakPtr<TextFieldPattern> pattern,
                               const RefPtr<TaskExecutor>& executor)
        : pattern_(pattern), executor_(executor) {}

    void InsertText(const std::string& text) {
        auto textFieldPattern = pattern_.Upgrade();
        CHECK_NULL_VOID(textFieldPattern);

        executor_->PostTaskToUI([textFieldPattern = pattern_, text]() {
            auto pattern = textFieldPattern.Upgrade();
            if (pattern) {
                pattern->HandleInsertText(text);
            }
        });
    }

    void DeleteBackward(int32_t length) {
        executor_->PostTaskToUI([weak = pattern_, length]() {
            auto pattern = weak.Upgrade();
            if (pattern) {
                pattern->HandleDeleteBackward(length);
            }
        });
    }

    void SendKeyboardStatus(int32_t status) {
        auto textFieldPattern = pattern_.Upgrade();
        CHECK_NULL_VOID(textFieldPattern);

        executor_->PostTaskToUI([this, status]() {
            auto pattern = pattern_.Upgrade();
            CHECK_NULL_VOID(pattern);
            pattern->HandleKeyboardStatus(status);
        });
    }

    void NotifySelectionChange(int32_t start, int32_t end) {
        executor_->PostTaskToUI([this, start, end]() {
            auto pattern = pattern_.Upgrade();
            CHECK_NULL_VOID(pattern);
            pattern->HandleSelectionChange(start, end);
        });
    }

