#include "bridge/declarative_frontend/jsview/js_view_abstract.h"
#include "core/components_ng/pattern/progress/progress_model_ng.h"

namespace OHOS::Ace::Framework {

void JSProgress::Create(const JSCallbackInfo& info)
{
    auto progressModel = ProgressModelNG::Create();
    if (info.Length() < 1) {
        return;
    }

    if (!info[0]->IsObject()) {
        LOGW("JSProgress::Create arg is not object");
    }

    auto params = info[0]->ToObject();
    auto value = params->GetProperty("value");
    auto total = params->GetProperty("total");

    progressModel->SetValue(value->ToNumber()->Value());
    progressModel->SetTotal(total->ToNumber()->Value());

    auto type = params->GetProperty("type");
    if (type->IsNumber()) {
        progressModel->SetType(static_cast<ProgressType>(type->ToNumber()->Int32Value()));
    }
}

void JSProgress::SetValue(const JSCallbackInfo& info)
{
    auto progressModel = ProgressModelNG::Create();
    if (info.Length() < 1) {
        return;
    }
    double value = info[0]->ToNumber()->Value();
    progressModel->SetValue(value);
    auto host = ViewStackModel::GetInstance()->GetFrameNodeByTag("Progress");
    if (host) {
        host->MarkDirtyNode(PROPERTY_UPDATE_MEASURE);
    }
}

void JSProgress::JsColor(const JSCallbackInfo& info)
{
    auto progressModel = ProgressModelNG::Create();
    if (info.Length() < 1) {
        return;
    }

    auto colorValue = info[0];
    if (colorValue->IsString()) {
        std::string colorStr = colorValue->ToString()->ToString();
        progressModel->SetColor(Color::FromString(colorStr));
    } else if (colorValue->IsNumber()) {
        uint32_t colorInt = colorValue->ToNumber()->Uint32Value();
        progressModel->SetColor(Color(colorInt));
    }
}

}
